// STEP 1: Parse Message - Dual Format (Cloud API + Twilio)
// Auto-detects incoming format and normalizes to common structure

try {
  const data = $input.first().json;
  const now = Date.now();
  let to, from, body, messageId, waId, profileName, hasMedia, mediaUrl, mediaType, isGroup, msgType;

  if (data.object === 'whatsapp_business_account') {
    // ========== CLOUD API FORMAT ==========
    const entry = data.entry?.[0];
    const change = entry?.changes?.[0];
    const value = change?.value;
    const message = value?.messages?.[0];
    const contact = value?.contacts?.[0];
    const metadata = value?.metadata;

    if (!message) {
      return {
        parseSuccess: false,
        error: true,
        errorType: 'not_a_message',
        errorMessage: 'Webhook event is not a message (possibly a status update)',
        timestamp: new Date().toISOString()
      };
    }

    to = metadata?.display_phone_number?.replace(/\\D/g, '') || metadata?.phone_number_id || '';
    from = (message.from || '').replace(/\\D/g, '');
    waId = contact?.wa_id || from;
    profileName = contact?.profile?.name || '';
    messageId = message.id || `msg_${now}`;
    msgType = message.type || 'text';
    hasMedia = false;

    if (msgType === 'text') {
      body = message.text?.body || '';
    } else if (['image', 'video', 'audio', 'document'].includes(msgType)) {
      body = message[msgType]?.caption || '';
      hasMedia = true;
      mediaUrl = message[msgType]?.id || null;
      mediaType = message[msgType]?.mime_type || msgType;
    } else if (msgType === 'location') {
      body = `Location: ${message.location?.latitude}, ${message.location?.longitude}`;
    } else if (msgType === 'contacts') {
      body = `Shared contact: ${message.contacts?.[0]?.name?.formatted_name || 'Unknown'}`;
    } else {
      body = '';
    }

    isGroup = false;
    mediaUrl = mediaUrl || null;
    mediaType = mediaType || null;

  } else {
    // ========== TWILIO FORMAT ==========
    to = (data.To || data.to || '').replace(/\\D/g, '');
    from = (data.From || data.from || '').replace(/\\D/g, '');
    waId = data.WaId || data.waId || from;
    profileName = data.ProfileName || data.profileName || '';
    messageId = data.MessageSid || data.messageSid || `msg_${now}`;
    body = data.Body || data.body || '';

    const numMedia = parseInt(data.NumMedia || data.numMedia || '0');
    hasMedia = numMedia > 0;
    mediaUrl = data.MediaUrl0 || data.mediaUrl0 || null;
    mediaType = data.MediaContentType0 || data.mediaContentType0 || null;

    isGroup = from.includes('-') ||
      (data.From || '').includes('@g.us') ||
      !!data.GroupId || !!data.groupId ||
      !!data.Participant || !!data.participant;

    if (!hasMedia) { msgType = 'text'; }
    else if (mediaType?.includes('image')) { msgType = 'image'; }
    else if (mediaType?.includes('video')) { msgType = 'video'; }
    else if (mediaType?.includes('audio')) { msgType = 'audio'; }
    else { msgType = 'document'; }
  }

  if (!to || !from) {
    throw new Error('Missing required fields: To or From');
  }

  // SECURITY: Sanitize message body
  body = (body || '').trim();
  body = body.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '');
  if (body.length > 2000) {
    body = body.substring(0, 2000);
  }

  return {
    messageId: messageId,
    to: to,
    from: from,
    waId: waId,
    body: body,
    type: msgType,
    isGroup: isGroup,
    groupId: isGroup ? (data.GroupId || data.groupId || from.split('-')[0]) : null,
    participant: isGroup ? (data.Participant || data.participant || from.split('-')[1]) : null,
    hasMedia: hasMedia,
    mediaUrl: mediaUrl,
    mediaType: mediaType,
    profileName: profileName,
    timestamp: new Date().toISOString(),
    processingStartTime: now,
    parseSuccess: true,
    sourceFormat: data.object === 'whatsapp_business_account' ? 'cloud_api' : 'twilio'
  };

} catch (error) {
  return {
    parseSuccess: false,
    error: true,
    errorType: 'parse_error',
    errorMessage: error.message,
    timestamp: new Date().toISOString()
  };
}

// STEP 4: Merge Agent Data
// SECURITY FIX: Separate sensitive fields from main data flow
// Access token is stored in _private (not passed to AI)

const message = $node['2 Block Groups?'].json;
const agentRecord = $input.first().json;
const fields = agentRecord.fields || agentRecord;

// SECURITY: Sensitive data stored separately - NOT passed downstream to AI
const _private = {
  whatsappAccessToken: fields.whatsapp_access_token || fields.cloud_api_access_token || '',
  whatsappBusinessAccountId: fields.whatsapp_business_account_id || '',
  whatsappPhoneNumberId: fields.whatsapp_phone_number_id || fields.cloud_api_phone_number_id || '',
  twilioSubAccountSid: fields.twilio_sub_account_sid || '',
  twilioAuthToken: fields.twilio_auth_token || ''
};

const agent = {
  recordId: agentRecord.id,
  id: fields.agent_id || agentRecord.id,
  name: fields.agent_name || 'Agent',
  email: fields.email || '',
  whatsappNumber: fields.whatsapp_number || '',
  companyName: fields.company_name || 'Real Estate Agency',
  region: fields.region || '',
  language: fields.language || 'en',
  timezone: fields.timezone || 'UTC',
  isActive: fields.is_active !== false,
  autoReply: fields.auto_reply !== false,
  isOnline: fields.is_online === true,
  lastSeen: fields.last_seen || null,
  onlineThresholdMinutes: parseInt(fields.online_threshold_minutes || '5'),
  googleCalendarId: fields.google_calendar_id || 'primary',
  airtableBaseId: fields.airtable_base_id || 'appzcZpiIZ6QPtJXT',
  aiModel: fields.ai_model || 'gpt-4',
  aiTemperature: parseFloat(fields.ai_temperature || '0.7'),
  maxResponseLength: parseInt(fields.max_response_length || '300'),
  primaryApi: fields.primary_api || 'cloud_api'
};

let currentlyOnline = agent.isOnline;
if (agent.lastSeen) {
  const minutesSinceLastSeen = (Date.now() - new Date(agent.lastSeen).getTime()) / 60000;
  if (minutesSinceLastSeen > agent.onlineThresholdMinutes) {
    currentlyOnline = false;
  }
}

return {
  messageId: message.messageId,
  from: message.from,
  to: message.to,
  waId: message.waId,
  body: message.body,
  type: message.type,
  profileName: message.profileName,
  hasMedia: message.hasMedia,
  mediaUrl: message.mediaUrl,
  mediaType: message.mediaType,
  agent: agent,
  agentId: agent.id,
  agentName: agent.name,
  agentRecordId: agent.recordId,
  agentIsOnline: currentlyOnline,
  replyTo: `whatsapp:+${message.from}`,
  replyFrom: `whatsapp:+${message.to}`,
  timestamp: message.timestamp,
  processingStartTime: message.processingStartTime,
  _private: _private
};

// STEP 6: Check Blocking Conditions
// SECURITY FIX: Strip _private from output so tokens don't flow to AI

const message = $node['4 Merge Agent Data'].json;
const contactResponse = $input.first().json;

let shouldBlock = false;
let blockReason = null;
let contactLabels = [];
let isPinned = false;

if (contactResponse && !contactResponse.error) {
  contactLabels = contactResponse.labels || [];
  isPinned = contactResponse.is_pinned === true || contactResponse.isPinned === true;

  const dntLabels = ['dnt', 'do not track', 'donottrack', 'no ai', 'noai', 'opt out', 'optout'];
  const hasDNT = contactLabels.some(label => {
    const labelName = (typeof label === 'string' ? label : label.name || '').toLowerCase().trim();
    return dntLabels.includes(labelName);
  });

  if (hasDNT) {
    shouldBlock = true;
    blockReason = 'dnt_label';
  } else if (isPinned) {
    shouldBlock = true;
    blockReason = 'contact_pinned';
  }
}

if (!shouldBlock && message.agentIsOnline) {
  shouldBlock = true;
  blockReason = 'agent_online';
}

// SECURITY: Build clean output WITHOUT _private tokens
const { _private, ...cleanMessage } = message;

return {
  ...cleanMessage,
  shouldBlock: shouldBlock,
  blockReason: blockReason,
  contactLabels: contactLabels,
  isPinned: isPinned,
  contactFetched: !contactResponse?.error
};

