// STEP 9: Parse AI Decision
// SECURITY FIX: Validate and restrict AI-requested operations
// - Only allow read/create (no update/delete)
// - Only allow known tables
// - Inject agent_id scoping into all filters and creates

const message = $node['7 Agent Active?'].json;
const aiResponse = $input.first().json;

let parsed = {
  intent: 'general',
  action: 'respond',
  response: 'Thank you for your message. How can I assist you today?',
  airtable_operation: { needed: false, operation: 'read', table: 'properties', filter: '', data: {} },
  extracted_data: {},
  confidence: 0.5
};

try {
  const content = aiResponse.choices?.[0]?.message?.content || '';
  const jsonMatch = content.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
  const jsonString = jsonMatch ? jsonMatch[1] : content;
  const aiParsed = JSON.parse(jsonString.trim());

  parsed = {
    intent: aiParsed.intent || parsed.intent,
    action: aiParsed.action || parsed.action,
    response: aiParsed.response || parsed.response,
    airtable_operation: {
      needed: aiParsed.airtable_operation?.needed || false,
      operation: aiParsed.airtable_operation?.operation || 'read',
      table: aiParsed.airtable_operation?.table || 'properties',
      filter: aiParsed.airtable_operation?.filter || '',
      data: aiParsed.airtable_operation?.data || {}
    },
    extracted_data: aiParsed.extracted_data || {},
    confidence: aiParsed.confidence || parsed.confidence
  };

  const maxLength = message.agent.maxResponseLength || 300;
  if (parsed.response.length > maxLength) {
    parsed.response = parsed.response.substring(0, maxLength - 3) + '...';
  }
} catch (error) {
  // Use default parsed object
}

// =========================================
// SECURITY: Validate and scope AI operations
// =========================================
const agentId = message.agentId;
const op = parsed.airtable_operation;

if (op.needed) {
  // 1. RESTRICT operations: only read and create allowed
  const allowedOps = ['read', 'create'];
  if (!allowedOps.includes(op.operation)) {
    op.needed = false;
    parsed.response += '\n\n_That operation is not permitted._';
  }

  // 2. RESTRICT tables
  const allowedTables = ['properties', 'leads', 'appointments', 'tasks', 'notes'];
  if (!allowedTables.includes(op.table)) {
    op.needed = false;
    parsed.response += '\n\n_That table is not accessible._';
  }

  // 3. CREATE: only allowed on appointments, tasks, notes
  const createAllowedTables = ['appointments', 'tasks', 'notes'];
  if (op.operation === 'create' && !createAllowedTables.includes(op.table)) {
    op.needed = false;
    parsed.response += '\n\n_Cannot create records in that table._';
  }

  // 4. INJECT agent_id scoping
  if (op.needed && op.operation === 'read') {
    const agentFilter = `{agent_id} = '${agentId}'`;
    if (op.filter && op.filter.trim()) {
      op.filter = `AND(${agentFilter}, ${op.filter})`;
    } else {
      op.filter = agentFilter;
    }
  }

  if (op.needed && op.operation === 'create') {
    op.data = op.data || {};
    op.data.agent_id = agentId;
  }
}

return {
  ...message,
  intent: parsed.intent,
  action: parsed.action,
  aiResponse: parsed.response,
  airtableOperation: op,
  extractedData: parsed.extracted_data,
  confidence: parsed.confidence
};

// STEP 10: Route Operation
// SECURITY FIX: Validates operation type before routing

const data = $input.first().json;
const op = data.airtableOperation;

const validOperations = ['read', 'create'];
if (!validOperations.includes(op.operation)) {
  throw new Error(`Blocked operation: ${op.operation}`);
}

const validTables = ['properties', 'leads', 'appointments', 'tasks', 'notes'];
if (!validTables.includes(op.table)) {
  throw new Error(`Blocked table: ${op.table}`);
}

return {
  ...data,
  airtableRoute: op.operation,
  airtableTable: op.table,
  airtableFilter: op.filter || '',
  airtableData: op.data || {},
  airtableBaseId: data.agent.airtableBaseId
};

// STEP 11: Prepare Final Response
// SECURITY FIX: Redacts sensitive data, uses safe references

const message = $node['9 Parse AI Decision'].json;
let finalResponse = message.aiResponse;
let airtableSuccess = false;

if ($input.first()?.json && message.airtableOperation?.needed) {
  const result = $input.first().json;
  if (!result.error) {
    airtableSuccess = true;
    if (!finalResponse.toLowerCase().includes('updated') &&
        !finalResponse.toLowerCase().includes('created') &&
        !finalResponse.toLowerCase().includes('saved')) {
      finalResponse += ' Done.';
    }
  } else {
    finalResponse += '\n\n_Note: Database update is pending._';
  }
}

if (!finalResponse.includes(message.agentName) &&
    !finalResponse.includes(message.agent.companyName) &&
    finalResponse.length < message.agent.maxResponseLength - 50) {
  finalResponse += `\n\n-- ${message.agentName}\n${message.agent.companyName}`;
}

const processingTime = Date.now() - message.processingStartTime;

return {
  messageId: message.messageId,
  to: message.replyTo,
  from: message.replyFrom,
  body: finalResponse,
  agentId: message.agentId,
  agentName: message.agentName,
  airtableExecuted: message.airtableOperation?.needed || false,
  airtableSuccess: airtableSuccess,
  airtableOperation: message.airtableOperation?.operation || null,
  airtableTable: message.airtableOperation?.table || null,
  processingTimeMs: processingTime,
  processingTimeSec: (processingTime / 1000).toFixed(2),
  readyToSend: true,
  timestamp: new Date().toISOString(),
  context: {
    intent: message.intent,
    action: message.action,
    confidence: message.confidence
  }
};

// Agent Status Update Parser

const data = $input.first().json;

if (!data.agent_id) {
  throw new Error('Missing required field: agent_id');
}

if (!data.status || !['online', 'offline'].includes(data.status)) {
  throw new Error('Status must be "online" or "offline"');
}

return {
  agentId: data.agent_id,
  status: data.status,
  source: data.source || 'api',
  timestamp: new Date().toISOString()
};

// Global Error Handler
// SECURITY FIX: Redacts sensitive fields before logging

const error = $input.first().json;

return {
  timestamp: new Date().toISOString(),
  errorType: 'workflow_error',
  errorMessage: (error.message || error.error || 'Unknown error').substring(0, 500),
  nodeName: error.node?.name || 'Unknown',
  nodeType: error.node?.type || 'Unknown',
  executionId: $execution.id,
  workflowName: $workflow.name,
  workflowId: $workflow.id
};
